            getter -> float { return self._balance; }
            setter(value: float) { self._balance = value; }
            deleter { self._balance = 0.0; }
        }

    # Pure computed (no backing): read-only by omitting `setter`.
    has doubled: float {
        getter { return self._balance * 2.0; }
    }
}

