    print l
    url = urlparse(l)

    path = url.path[1:].split("/")
    tmp = url.netloc
    for i in range(0, len(path)-1):
        tmp += "/"+path[i]
    if not os.path.exists(tmp):
        os.makedirs(tmp)  
    name = path[len(path)-1]
    if name == "":
