        newItem = {
            "itemId": itemId,
            "role": role,
            "content": content,
            "timestamp": Date.now()
        };
        transcript = lambda prev: any  -> any { return prev.concat([newItem]); };
    }
    # Add a transcript item by itemId (for realtime messages)
    def addTranscriptItem(
        itemId: str, role: str, content: str, thinking: any = None
    ) -> None {
        newItem = {
            "itemId": itemId,
            "role": role,
            "content": content,
            "thinking": thinking,
            "timestamp": Date.now()
        };
        transcript = lambda prev: any  -> any { 
            exists = prev.some(
                lambda item: any  -> bool { return item.itemId == itemId; }
            );
            if exists {
                return prev;
            }
            return prev.concat([newItem]);
        };
    }
    # Update a transcript item by itemId
    def updateTranscriptItem(itemId: str, content: str, thinking: Any = None) -> None {
        transcript = lambda prev: any  -> any { 
            return [
                (
                    lambda item: any  -> any { 
                        if item.itemId == itemId {
                            updatedItem = {
                                "itemId": item.itemId,
                                "role": item.role,
                                "content": content,
                                "timestamp": item.timestamp
                            };
                            # Add thinking data if provided or preserve existing
                            thinkingValue = thinking
                                if thinking != None
                                else (item.thinking if item.thinking else None);
                            if thinkingValue != None {
                                updatedItem["thinking"] = thinkingValue;
                            }
                            return updatedItem;
                        }return item; 
                    }
                )(item) for item in prev
            ];
        };
    }
    # Append text to a transcript item by itemId (for streaming)
    def appendTranscriptItem(itemId: str, deltaText: str) -> None {
