    }
    if not isinstance(prs, list) {
        return grouped;
    }
    for pr in prs {
        n = int(pr.get("number", 0));
        try {
            files = requests.get(
                f"{GH_API}/repos/{gh_repo()}/pulls/{n}/files",
                headers=gh_headers(token), params={"per_page": 100}, timeout=30,
            ).json();
