            continue;
        }
        if not isinstance(files, list) {
            continue;
        }
        touched: list = [];
        for f in files {
            fn = str(f.get("filename", ""));
            if fn in path_to_slug {
                s = str(path_to_slug[fn]);
                if s not in touched {
                    touched.append(s);
                }
            }
        }
        if not touched {
            continue;
